CREATE OR REPLACE FUNCTION OFSERM.ABL_INVESTMENT_EXPOSURE_DATA_CREATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_INVESTMENT_EXPOSURES(N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_UNDERLYING_TYPE_SKEY,N_GAAP_SKEY,F_DIVERSIFIED_FLAG,F_EQUITY_GRANDFATHERED_FLAG,F_INSTR_PORT_INFO_RECD_FLAG,N_INSTRUMENT_SKEY,N_ISSUE_SKEY,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_ISSUER_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,F_DEBT_HOLDING_IND,F_EQUITY_POSITION_FLAG,F_INTERNAL_CUST_IND,F_LONG_TERM_INVESTMENT_FLAG,F_NETTABILITY_FLAG,F_PARENT_FIDUCIARY_ACCT_IND,F_PAST_DUE_FLAG,F_PERIODIC_CASH_FLOW_FLAG,F_REGULATORY_PARTY_INDICATOR,F_REG_CAP_INVST_IND,F_SOLVENCY_IND,F_TREASURY_STOCK_INDICATOR,N_ACCRUED_INT,N_CCF_PERCENT,N_CCF_PERCENT_DRAWN,N_CURR_12M_ECL,N_ENTITY_SKEY,N_EXCHANGE_RATE,N_EXPOSURE_AMOUNT,N_EXP_MTM_VALUE,N_GROUP_ASSET_SIZE,N_ORIGINAL_MATURITY,N_INSTR_OTH_VALUATION_ADJ_AMT,N_PARENT_ACCT_SKEY,N_PARENT_FIDUCIARY_ACCT_SKEY,N_PRE_MITIGATION_RWA_EL,N_RESIDUAL_MATURITY,N_RUN_PARAMETER_SETUP_SKEY,N_RUN_SKEY,N_CUST_ANNUAL_SALES,N_SHAREHOLDING_PERCENT,N_UNDRAWN_AMOUNT,N_INSTR_VALUATION_ADJ_AMOUNT,N_WRITE_OFF_AMT,V_APPROACH_TYPE,V_CCY_CODE,V_EXP_RCY_CODE,N_REG_CAP_ACCT_PURPOSE_SKEY,F_CREDIT_IMPAIRMENT_FLAG,F_DR_MATERIALITY_FLAG,F_FINANCIAL_ASSET_IFRS9_FLAG,F_PREF_TREATMENT_FLAG,F_RW_BY_DISCRETION,N_ADJUSTED_LGD_PERCENT,N_CCF_OWN_ESTIMATE,N_EFF_MATURITY,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,N_PROVISION_AMOUNT,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,N_STD_SENIORITY_SKEY,F_EXP_DEFAULTED_FLAG,F_AUTO_CANCELLATION_FLAG,F_BUYER_SELLER_IND,F_CAPITAL_NETTING_QUAL_FLAG,F_CORE_MKT_PARTICIPANT_FLAG,F_DVP_FLAG,F_EQUITY_TRADED_FLAG,F_EXP_HELD_AT_FAIR_VALUE,F_FAILED_TRADE_FLAG,F_GUAR_BY_SOVERIGN_IND,F_MATERIALITY_FLAG,F_QUAL_REF_OBLIG_IND,F_RECIPROCAL_CROSS_HLDG_IND,F_SECURED_IND,F_SENIOR_CLAIM_FLAG,F_TRS_ASSET_OFFSETTING,F_UNCOND_CANCELLED_EXP_IND,N_RESIDUAL_VALUE,N_EXP_SENIORITY,N_FAILED_BUSINESS_DAYS,N_LOAD_RUN_ID,N_MIN_HOLDING_PERIOD,N_REMARGIN_FREQUENCY)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_EXPOSURE_UNDERLYING_TYPE.N_UNDERLYING_TYPE_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),DIM_INSTRUMENT_CONTRACT.F_DIVERSIFIED_FLAG,DIM_INSTRUMENT_CONTRACT.F_GRANDFATHERED_IND,DIM_INSTRUMENT_CONTRACT.F_PERIOD_PORT_INFO_RECD_FLAG,to_char(DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),CASE  WHEN DIM_BASEL_PRODUCT_TYPE.V_BASEL_PROD_TYPE_CODE IN ( 'DSE' ,'HDCI' ,'PDI' ,'BB' ,'BND' ,'CPPS' ,'CB' ,'INNV' ,'NCPPS' ,'PPSS' ,'PERBND' ,'TXB' ,'TEB' ,'UPS' ) THEN 'Y' ELSE 'N' END,CASE WHEN STG_INVESTMENTS.F_SHORT_POSITION_IND='Y' THEN 'S' ELSE 'L' END,CASE  WHEN INTERNAL_ENTITY.N_RUN_SKEY IS NOT NULL THEN 'Y' ELSE 'N' END,CASE WHEN (STG_INVESTMENTS.D_MATURITY_DATE - STG_INVESTMENTS.D_START_DATE)/365 > 5 THEN 'Y'ELSE 'N' END,CASE WHEN COALESCE(STG_INVESTMENTS.f_contract_walk_away_ind,'N') = 'Y' THEN 'N' ELSE STG_INVESTMENTS.f_nettability_flag END,CASE WHEN STG_INVESTMENTS.V_PARENT_FIDUCIARY_ACCT_NUMBER IS NOT NULL THEN 'Y' ELSE 'N' END,CASE WHEN COALESCE(DIM_INSTRUMENT_CONTRACT.V_BOND_STATUS_CD,'Z') = 'P' THEN 'Y' ELSE 'N' END,CASE WHEN STG_INVESTMENTS.N_EQUITY_DIVIDEND_PERCENT IS NOT NULL THEN 'Y' ELSE 'N' END,DIM_ORG_STRUCTURE_REG.F_REGULATORY_ENTITY_IND,NVL(DIM_INSTRUMENT_CONTRACT.F_REG_CAP_INVST_IND,STG_INVESTMENTS.F_REG_CAP_INVST_IND),NVL(DIM_INSTRUMENT_CONTRACT.F_SOLVENCY_IND,STG_INVESTMENTS.F_SOLVENCY_IND),CASE WHEN FCT_ENTITY_INFO.V_PARTY_ID = STG_INVESTMENTS.V_ISSUER_CODE THEN 'Y' ELSE 'N' END,STG_INVESTMENTS.N_ACCRUED_INTEREST * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,'1','1',CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,NVL(DIM_INSTRUMENT_CONTRACT.N_ENTITY_SKEY,FCT_ENTITY_INFO.N_ENTITY_SKEY),FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_INVESTMENTS.N_EOP_BAL * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_INVESTMENTS.N_EXP_MTM_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,DAYS_BETWEEN(STG_INVESTMENTS.D_EFFECTIVE_DATE,STG_INVESTMENTS.D_MATURITY_DATE,STG_INVESTMENTS.V_DAY_COUNT_IND),FSI_INSTR_VALUATION_DETAILS.N_OTHER_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,DIM_PARENT_EXPOSURE.N_ACCT_SKEY,PARENT_FIDUCIARY_ACCT.n_acct_skey,'0',DAYS_BETWEEN(STG_INVESTMENTS.FIC_MIS_DATE,STG_INVESTMENTS.D_MATURITY_DATE,STG_INVESTMENTS.V_DAY_COUNT_IND),CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY ELSE NULL END,'870',FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,STG_INVESTMENTS.N_UNDRAWN_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_INSTR_VALUATION_DETAILS.N_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_INVESTMENTS.N_WRITE_OFF_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE ELSE NULL END,NVL(DIM_INSTRUMENT_CONTRACT.V_CCY_CODE,STG_INVESTMENTS.V_CCY_CODE),RUN_EXE_PARAMETERS_RCY.V_PARAM_VALUE_CODE,to_char(FSI_ACCOUNT_PURPOSE_RECLASS.N_REG_CAP_ACCT_PURPOSE_SKEY),FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_DR_MATERIALITY_FLAG,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,FSI_ACCT_MODELING_INFO.F_PREF_TREATMENT_FLAG,FSI_ACCT_MODELING_INFO.F_RW_BY_DISCRETION,to_char(FSI_ACCT_MODELING_INFO.N_ADJUSTED_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE),to_char(FSI_ACCT_MODELING_INFO.N_EFF_MATURITY),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_PROVISION_AMOUNT),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(FSI_SENIORITY_RECLASSIFICATION.N_STD_SENIORITY_SKEY),STG_INVESTMENTS.F_ACCT_DEFAULTED_FLAG,STG_INVESTMENTS.F_AUTO_CANCELLATION_FLAG,STG_INVESTMENTS.F_BUY_SELL_IND,STG_INVESTMENTS.F_CAPITAL_NETTING_QUAL_FLAG,STG_INVESTMENTS.F_CORE_MKT_PARTICIPANT_FLAG,STG_INVESTMENTS.F_DVP_FLAG,STG_INVESTMENTS.F_EQUITY_TRADED_FLAG,STG_INVESTMENTS.F_EXP_HELD_AT_FAIR_VALUE,STG_INVESTMENTS.F_FAILED_TRADE_FLAG,STG_INVESTMENTS.F_GUAR_BY_SOVERIGN_IND,STG_INVESTMENTS.F_MATERIALITY_FLAG,STG_INVESTMENTS.F_QUAL_REF_OBLIG_IND,STG_INVESTMENTS.F_RECIPROCAL_CROSS_HLDG_IND,STG_INVESTMENTS.F_SECURED_IND,STG_INVESTMENTS.F_SENIOR_CLAIM_FLAG,STG_INVESTMENTS.F_TRS_ASSET_OFFSETTING,STG_INVESTMENTS.F_UNCOND_CANCELLED_EXP_IND,to_char(STG_INVESTMENTS.N_CONTRACT_QUANTITY),to_char(STG_INVESTMENTS.N_EXP_SENIORITY),to_char(STG_INVESTMENTS.N_FAILED_BUSINESS_DAYS),to_char(STG_INVESTMENTS.N_LOAD_RUN_ID),to_char(STG_INVESTMENTS.N_MIN_HOLDING_PERIOD),to_char(STG_INVESTMENTS.N_REMARGIN_FREQUENCY) FROM STG_INVESTMENTS INNER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = STG_INVESTMENTS.FIC_MIS_DATE AND STG_INVESTMENTS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND COALESCE(STG_INVESTMENTS.F_CAPITAL_CHARGE_EXCLUSION, 'N') <> 'Y' AND COALESCE(STG_INVESTMENTS.F_CLOSED_IND, 'N') <> 'Y' AND COALESCE(STG_INVESTMENTS.F_SECURITIZED_FLAG, 'N') <> 'Y' LEFT JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_INVESTMENTS.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE LEFT JOIN DIM_INSTRUMENT_TYPE ON DIM_INSTRUMENT_TYPE.V_INSTR_TYPE_CODE = DIM_INSTRUMENT_CONTRACT.V_INSTR_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_TYPE.D_RECORD_START_DATE AND DIM_INSTRUMENT_TYPE.D_RECORD_END_DATE INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY INNER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' AND FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG = 'N' INNER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'INV_NON_SEC_EXP' INNER JOIN FCT_ENTITY_INFO ON STG_INVESTMENTS.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE AND FCT_ENTITY_INFO.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'N') = 'Y' LEFT JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY INNER JOIN DIM_EXPOSURE DIM_EXPOSURE ON STG_INVESTMENTS.V_ACCOUNT_NUMBER = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE LEFT JOIN DIM_EXPOSURE DIM_PARENT_EXPOSURE ON STG_INVESTMENTS.V_PARENT_EXPOSURE_ID = DIM_PARENT_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARENT_EXPOSURE.d_record_start_date AND DIM_PARENT_EXPOSURE.d_record_end_date LEFT JOIN DIM_PARTY ON STG_INVESTMENTS.V_ISSUER_CODE = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE LEFT JOIN DIM_ORG_STRUCTURE DIM_ORG_STRUCTURE_REG ON DIM_ORG_STRUCTURE_REG.V_PARTY_ID = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE_REG.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE_REG.D_RECORD_END_DATE INNER JOIN DIM_PARTY_TYPE ON DIM_PARTY.V_PARTY_TYPE = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE LEFT JOIN DIM_PRODUCT ON STG_INVESTMENTS.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE LEFT JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY LEFT JOIN DIM_GAAP ON DIM_GAAP.V_GAAP_CODE = STG_INVESTMENTS.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT JOIN DIM_COUNTRY ON DIM_COUNTRY.V_COUNTRY_ID = STG_INVESTMENTS.V_COUNTRY_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE LEFT JOIN DIM_EXPOSURE_UNDERLYING_TYPE ON DIM_EXPOSURE_UNDERLYI